-text-main:#f8fafc;--text-muted:#a1a1aa;--accent-gradient:linear-gradient(135deg, #f43f5e, #8b5cf6);--accent-glow:rgba(244, 63, 94, 0.4);--res-card-bg:rgba(255, 255, 255, 0.02);--res-border:rgba(255, 255, 255, 0.08);--res-accent:#f43f5e}body{background:var(--bg-color);color:var(--text-main);font-family:Inter,sans-serif;padding-top:120px;background-image:radial-gradient(circle at 50% 0,rgba(139,92,246,.1) 0,transparent 50%);background-repeat:no-repeat;min-height:100vh}.navbar-custom{background:rgba(18,18,20,.7);border-bottom:1px solid var(--border-color);backdrop-filter:blur(12px);padding:16px 0;position:fixed;top:0;left:0;width:100%;z-index:999}.card-premium{background:var(--card-bg);border:1px solid var(--border-color);border-radius:20px;box-shadow:0 20px 40px rgba(0,0,0,.5),inset 0 1px 0 rgba(255,255,255,.05);backdrop-filter:blur(10px)}.title-gradient{background:var(--accent-gradient);-webkit-background-clip:text;-webkit-text-fill-color:transparent;font-weight:800;letter-spacing:-1px}.btn-start,.mode-btn{font-weight:600;font-size:14px;position:relative}input.form-control,textarea.form-control{background:rgba(0,0,0,.4);border:1px solid var(--border-color);color:var(--text-main);border-radius:12px;padding:15px;font-size:14px;transition:.3s cubic-bezier(.4, 0, .2, 1)}input.form-control:focus,textarea.form-control:focus{background:rgba(0,0,0,.6);border-color:#8b5cf6;box-shadow:0 0 0 4px rgba(139,92,246,.15);outline:0;color:var(--text-main)}input.form-control::placeholder,textarea.form-control::placeholder{color:#52525b}.btn-start{background:var(--accent-gradient);border:none;color:#fff;border-radius:12px;text-transform:uppercase;letter-spacing:1px;transition:.3s;overflow:hidden;z-index:1}.field-label,.stat-label{color:var(--text-muted);letter-spacing:1.5px;text-transform:uppercase}.btn-start::before{content:'';position:absolute;top:0;left:0;width:100%;height:100%;background:linear-gradient(135deg,#8b5cf6,#f43f5e);z-index:-1;transition:opacity .3s;opacity:0}.btn-start:hover::before{opacity:1}.btn-start:hover{transform:translateY(-2px);box-shadow:0 8px 20px var(--accent-glow);color:#fff}.mode-switcher{background:rgba(0,0,0,.4);border:1px solid rgba(255,255,255,.08);border-radius:12px;padding:6px;display:inline-flex;margin-bottom:30px;box-shadow:inset 0 2px 4px rgba(0,0,0,.3)}.mode-btn{background:0 0;color:var(--text-muted);border:none;padding:12px 35px;border-radius:8px;transition:.3s cubic-bezier(.4, 0, .2, 1);cursor:pointer}.action-pill,.premium-ui-card{border:1px solid var(--res-border)}.action-pill,.nav-btn-icon{transition:.2s;cursor:pointer}.mode-btn:hover:not(.active){color:#fff;background:rgba(255,255,255,.03)}.mode-btn.active{background:var(--accent-gradient);color:#fff;box-shadow:0 4px 15px rgba(244,63,94,.3)}.stat-num{font-size:36px;font-weight:700}.stat-label{font-size:11px;font-weight:700}.premium-ui-card{border-radius:16px;background:var(--res-card-bg);overflow:hidden;width:100%}.action-pill,.card-head{background:rgba(255,255,255,.01)}.card-head{border-bottom:1px solid var(--res-border);padding:18px 24px}.card-body-pad{padding:24px 24px 30px}.field-label{font-size:10px;font-weight:700;margin-bottom:6px}.field-value{font-size:15px;color:var(--text-main);font-weight:600}.email-value{font-size:22px;font-weight:700;word-break:break-all;letter-spacing:.5px}.action-pill,.carousel-indicator{text-align:center;font-weight:600;letter-spacing:.5px}.action-pill-group{display:flex;margin-top:1.5rem;gap:12px}.action-pill{flex:1 1 0;color:var(--text-main);padding:12px 0;border-radius:12px;font-size:13px;text-decoration:none;display:inline-block}.action-pill:hover{background:rgba(244,63,94,.1);color:#f43f5e;border-color:#f43f5e;text-decoration:none;box-shadow:0 4px 12px rgba(244,63,94,.2)}.carousel-wrapper{display:flex;align-items:center;justify-content:center;gap:20px;position:relative;padding:10px 0}.carousel-viewport{flex-grow:1;overflow:hidden;position:relative}.carousel-card{display:none;width:100%;animation:.3s ease-in-out forwards fadeScale}.carousel-card.active{display:block}@keyframes fadeScale{from{opacity:0;transform:scale(.98)}to{opacity:1;transform:scale(1)}}.nav-btn-icon{background:rgba(255,255,255,.05);border:1px solid var(--res-border);color:var(--text-muted);width:44px;height:44px;border-radius:50%;display:inline-flex;align-items:center;justify-content:center;font-size:16px;flex-shrink:0}.nav-btn-icon:hover:not(:disabled){color:#f43f5e;background:rgba(244,63,94,.15);border-color:#f43f5e;box-shadow:0 4px 12px rgba(244,63,94,.3)}.nav-btn-icon:disabled{opacity:.3;cursor:not-allowed}.carousel-indicator{color:var(--text-muted);font-size:14px;margin-top:20px}.status-badge{font-size:10px;padding:6px 12px;border-radius:8px;font-weight:700;letter-spacing:.5px;text-transform:uppercase}.status-error{background:rgba(239,68,68,.1);color:#f87171;border:1px solid rgba(239,68,68,.2)}.status-warning{background:rgba(245,158,11,.1);color:#fbbf24;border:1px solid rgba(245,158,11,.2)}.fade-in{animation:.5s cubic-bezier(.16,1,.3,1) forwards fadeIn}@keyframes fadeIn{from{opacity:0;transform:translateY(15px)}to{opacity:1;transform:translateY(0)}}.loader{border:3px solid rgba(255,255,255,.1);border-top:3px solid #f43f5e;border-radius:50%;width:20px;height:20px;animation:1s linear infinite spin;display:inline-block;vertical-align:middle;margin-right:8px}@keyframes spin{0%{transform:rotate(0)}100%{transform:rotate(360deg)}}.modal-backdrop{position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.7);backdrop-filter:blur(5px);z-index:1050;display:flex;align-items:center;justify-content:center}.modal-content{background:var(--card-bg);border:1px solid var(--border-color);border-radius:16px;padding:24px;width:90%;max-width:420px;box-shadow:0 20px 40px rgba(0,0,0,.5)}@media (max-width:768px){body{padding-top:115px}.navbar-custom h1{font-size:1.2rem!important}.card-premium{padding:20px!important}.title-gradient{font-size:2.2rem!important}#bulkInput{height:200px}.stat-num{font-size:28px}.stat-label{font-size:9px;letter-spacing:1px}.card-body-pad{padding:20px 16px 24px}.email-value{font-size:18px}.field-value{font-size:13px}.field-label{font-size:9px}.action-pill{font-size:11px;padding:10px 0}.action-pill-group{gap:8px}.carousel-wrapper{gap:10px}.nav-btn-icon{width:36px;height:36px;font-size:14px}}@media (max-width:480px){.mode-switcher{display:flex;width:100%}.mode-btn{flex:1;padding:10px 0;font-size:13px}#bulkStats{flex-wrap:wrap;gap:15px}#bulkStats>div{flex:1 1 30%}.action-pill-group{flex-direction:column;gap:10px}.action-pill{width:100%}} </style></head><body><nav class="navbar-custom"><div class="container d-flex justify-content-between align-items-center"><div class="d-flex align-items-center"><img src="waguri1.png" alt="Waguri Logo" class="mr-3" style="width: 56px; height: 56px; object-fit: contain; border-radius: 12px;"><h1 class="title-gradient m-0" style="font-size: 1.5rem; letter-spacing: 0;">Waguri NF Checker</h1></div><div class="text-muted d-none d-sm-block" style="font-size: 0.9rem; font-weight: 500; letter-spacing: 0.5px;"> Secure & Premium Token Auth </div></div></nav><div id="formatModal" class="modal-backdrop" style="display: none;"><div class="modal-content fade-in"><div class="d-flex justify-content-between align-items-center mb-3"><h5 class="text-white font-weight-bold m-0"><i class="fas fa-exclamation-circle text-[#f43f5e] mr-2"></i> Requirement Notice</h5><button onclick="closeModal()" class="text-muted bg-transparent border-0" style="cursor: pointer; font-size: 1.2rem;"><i class="fas fa-times"></i></button></div><p style="color: var(--text-muted); font-size: 14px; line-height: 1.6;"> Requires <strong class="text-white">SecureNetflixId</strong> and <strong class="text-white">NetflixId</strong>. To guarantee accurate cookie validation, please confirm that your session data contains both fields. </p><button onclick="closeModal()" class="btn btn-start w-100 mt-3 py-2">Understood</button></div></div><div id="mobileGuideModal" class="modal-backdrop" style="display: none;"><div class="modal-content fade-in" style="max-width: 500px;"><div class="d-flex justify-content-between align-items-center mb-4"><h5 class="text-white font-weight-bold m-0"><i class="fas fa-mobile-alt text-[#f43f5e] mr-2"></i> Watch on Mobile Guide</h5><button onclick="closeMobileGuide()" class="text-muted bg-transparent border-0" style="cursor: pointer; font-size: 1.2rem;"><i class="fas fa-times"></i></button></div><div style="color: var(--text-muted); font-size: 13px; line-height: 1.6; max-height: 60vh; overflow-y: auto; padding-right: 5px;"><p class="text-white mb-3 font-weight-bold" style="font-size: 14px;">To Watch on Mobile App is 50/50 but there still a chance! This method works for some devices, just try and try!</p><ol class="pl-3 mb-4" style="list-style-type: decimal;"><li class="mb-2">Open Netflix App (Make sure it's <strong>Clear Data</strong>). Leave it open.</li><li class="mb-2">Make sure you're using our website in <strong>Chrome</strong> (Better chances based on some users).</li><li class="mb-2">Now click the "<strong>WATCH ON MOBILE</strong>" button below.</li><li class="mb-2">If an 'Open App' prompt shows in the browser, click it and it will direct to the Netflix app.</li></ol><div class="p-3 mb-3" style="background: rgba(244, 63, 94, 0.05); border-left: 3px solid #f43f5e; border-radius: 0 8px 8px 0;"><p class="text-[#f43f5e] font-weight-bold mb-1" style="font-size: 14px;">If this didn't work:</p><p class="mb-0 text-gray-300">Click the <strong>Web Button</strong> first. It will direct to a new tab. Now go back to the Checker again and click the Watch on Mobile again. Some say this works. Just try and try. This is depending on Device and Browsers.</p></div></div><a id="actualMobileLink" href="#" target="_blank" class="btn btn-start w-100 mt-2 py-3 text-center" style="display: block; text-decoration: none;"><i class="fas fa-external-link-alt mr-2"></i> WATCH ON MOBILE </a></div></div><div id="tvGuideModal" class="modal-backdrop" style="display: none;"><div class="modal-content fade-in" style="max-width: 500px;"><div class="d-flex justify-content-between align-items-center mb-3"><h5 class="text-white font-weight-bold m-0"><i class="fas fa-tv text-[#f43f5e] mr-2"></i> Watch on TV Guide</h5><button onclick="closeTvGuide()" class="text-muted bg-transparent border-0" style="cursor: pointer; font-size: 1.2rem;"><i class="fas fa-times"></i></button></div><div style="color: var(--text-muted); font-size: 13px; line-height: 1.6; max-height: 60vh; overflow-y: auto; padding-right: 5px;"><div class="mb-4 d-flex align-items-center gap-2"><input type="text" id="tvLinkInput" class="form-control" readonly style="flex: 1; margin-bottom: 0; padding: 12px; font-size: 12px; background: rgba(0,0,0,0.5);"><button onclick="copyTvLink()" class="btn btn-start py-2 px-3" style="margin-bottom: 0; min-width: 80px;"><i class="fas fa-copy"></i> Copy</button></div><p class="text-white mb-4 font-weight-bold" style="font-size: 14px;">To watch Netflix on your TV is high chance especially if you have a PC or a Laptop.</p><div class="mb-4"><p class="text-[#f43f5e] font-weight-bold mb-1" style="font-size: 14px;">Option 1 (PC/Laptop)</p><p class="mb-0 text-gray-300">If you have a PC/Laptop, kindly click the <strong>Web</strong> button first. After it directly logs you in, copy the highlighted link from this modal or press Copy, paste it into your browser's address bar, and enter the code shown on your TV.</p></div><div class="mb-2"><p class="text-[#f43f5e] font-weight-bold mb-1" style="font-size: 14px;">Option 2 (Mobile)</p><p class="mb-0 text-gray-300">If you only have mobile, kindly click the <strong>Mobile Guide</strong> button. After it directly logs you into the Netflix application, simply scan the QR code displayed on your Netflix TV screen using your device.</p></div></div></div></div><div class="container pb-5"><div class="row justify-content-center"><div class="col-md-10 col-lg-9"><div class="card-premium p-4 p-md-5 mb-4 relative z-10" id="inputContainer"><div class="text-center"><div class="mode-switcher"><button class="mode-btn active" id="btnTabSingle" onclick="switchTab('single')">Single Check</button><button class="mode-btn" id="btnTabBulk" onclick="switchTab('bulk')">Bulk Check</button></div></div><div id="sectSingle" class="fade-in"><label class="font-weight-bold mb-2 text-white" style="font-size: 14px;">Input Single Cookie</label><textarea id="singleInput" class="form-control mb-4" rows="4" style="resize: none; overflow-y: auto;" placeholder="Paste single Netscape block, JSON, or NetflixId here..."></textarea><button id="startSingleBtn" class="btn btn-start w-100 py-3" onclick="processSingle()"><i class="fas fa-bolt mr-2"></i> CHECK ACCOUNT </button></div><div id="sectBulk" style="display: none;"><div class="d-flex justify-content-between align-items-end mb-2"><label class="font-weight-bold text-white mb-0" style="font-size: 14px;">Paste Bulk Cookies</label><span style="font-size: 12px; color: #f43f5e; cursor: pointer; transition: 0.2s;" onclick="openModal()"><i class="fas fa-info-circle"></i> Supported Formats</span></div><p class="mb-3" style="font-size: 12px; color: var(--text-muted);"> Paste one cookie per line or use universal separator ( | ). Netscape and JSON blocks are automatically parsed. </p><textarea id="bulkInput" class="form-control mb-4" rows="12" style="resize: none; overflow-y: auto;" placeholder="Format: NetflixId=... | SecureNetflixId=...&#10;Or paste full JSON/Netscape formats..."></textarea><button id="startBulkBtn" class="btn btn-start w-100 py-3" onclick="processBulk()"><i class="fas fa-layer-group mr-2"></i> START BULK CHECK </button></div></div><div class="card-premium p-4 p-md-5" id="resultsCard" style="display: none;"><div id="resultsHeader" class="d-flex justify-content-between align-items-center mb-4 pb-3" style="border-bottom: 1px solid var(--border-color);"><h5 class="font-weight-bold text-white m-0"><i class="fas fa-satellite-di